                if (spoolmanInventoryUpdate.NoteOption.Value != null)
                    writer.WriteString("note", spoolmanInventoryUpdate.Note);
                else
                    writer.WriteNull("note");

            if (spoolmanInventoryUpdate.CostPerKgOption.IsSet)
                if (spoolmanInventoryUpdate.CostPerKgOption.Value != null)
                    writer.WriteNumber("cost_per_kg", spoolmanInventoryUpdate.CostPerKgOption.Value!.Value);
                else
                    writer.WriteNull("cost_per_kg");

            if (spoolmanInventoryUpdate.TagUidOption.IsSet)
                if (spoolmanInventoryUpdate.TagUidOption.Value != null)
                    writer.WriteString("tag_uid", spoolmanInventoryUpdate.TagUid);
                else
                    writer.WriteNull("tag_uid");

            if (spoolmanInventoryUpdate.TrayUuidOption.IsSet)
                if (spoolmanInventoryUpdate.TrayUuidOption.Value != null)
                    writer.WriteString("tray_uuid", spoolmanInventoryUpdate.TrayUuid);
                else
                    writer.WriteNull("tray_uuid");

            if (spoolmanInventoryUpdate.StorageLocationOption.IsSet)
                if (spoolmanInventoryUpdate.StorageLocationOption.Value != null)
                    writer.WriteString("storage_location", spoolmanInventoryUpdate.StorageLocation);
                else
                    writer.WriteNull("storage_location");

            if (spoolmanInventoryUpdate.SlicerFilamentOption.IsSet)
                if (spoolmanInventoryUpdate.SlicerFilamentOption.Value != null)
                    writer.WriteString("slicer_filament", spoolmanInventoryUpdate.SlicerFilament);
                else
                    writer.WriteNull("slicer_filament");

            if (spoolmanInventoryUpdate.SlicerFilamentNameOption.IsSet)
                if (spoolmanInventoryUpdate.SlicerFilamentNameOption.Value != null)
                    writer.WriteString("slicer_filament_name", spoolmanInventoryUpdate.SlicerFilamentName);
                else
                    writer.WriteNull("slicer_filament_name");
        }
    }
}
